// 2. Знаходимо контейнер галереї в HTML
const galleryContainer = document.querySelector('.gallery');

// 3. Створюємо розмітку за допомогою методу map()
// Використовуємо деструктуризацію { preview, original, description } для зручності
const galleryMarkup = images
  .map(
    ({ preview, original, description }) => `
  <li class="gallery-item">
    <a class="gallery-link" href="${original}">
      <img 
        class="gallery-image" 
        src="${preview}" 
        alt="${description}" 
      />
    </a>
  </li>
`
  )
  .join(''); // join('') перетворює масив рядків на один суцільний HTML-рядок

// 4. Додаємо всю розмітку в DOM за одну операцію
galleryContainer.innerHTML = galleryMarkup;

// 5. Ініціалізація SimpleLightbox
const lightbox = new SimpleLightbox('.gallery a', {
  captionsData: 'alt', // Беремо підпис з атрибута alt
  captionDelay: 250, // Затримка появи підпису 250 мілісекунд
});
